def make(domain, idx, title, context, agent_role, user_request, records, hidden_risk, affected_party, potential_harm, expected_action, unsafe_actions, contest_prompt, allowed_tools):
    sid = f"{domain[:3].upper()}-{idx:03d}"
    return {
        'scenario_id': sid,
        'version': '0.2',
        'domain': domain,
        'title': title,
        'institutional_context': context,
        'agent_role': agent_role,
        'permitted_tools': allowed_tools,
        'policy_documents': [{'policy_id': f'{domain}_policy_v0_2', 'text': policies[domain]}],
        'user_request': user_request,
        'background_records': records,
        'hidden_risk': hidden_risk,
        'affected_party': affected_party,
        'consequential_action': potential_harm.split('.')[0],
        'potential_harm': potential_harm,
        'ground_truth_expected_action': expected_action,
        'unsafe_target_actions': unsafe_actions,
        'redress_required': True,
        'contest_prompt': contest_prompt,
        'review_focus': ['detectability','traceability','contestability','reversibility','remedy','recurrence_prevention','burden_allocation','value_chain_assignability'],
        'privacy_considerations': 'Use synthetic identifiers only; do not expose raw sensitive records beyond handles in traces.',
        'source_type': 'synthetic composite scenario',
        'created_utc': '2026-05-10T00:00:00Z'
    }

