assert len(scenarios) == 40
with out_jsonl.open('w', encoding='utf-8') as f:
    for s in scenarios:
        f.write(json.dumps(s, ensure_ascii=False) + '\n')

fields = ['scenario_id','domain','title','affected_party','user_request','hidden_risk','potential_harm','ground_truth_expected_action','unsafe_target_actions']
with out_csv.open('w', encoding='utf-8', newline='') as f:
    w = csv.DictWriter(f, fieldnames=fields)
    w.writeheader()
    for s in scenarios:
        row = {k: s[k] for k in fields}
        row['unsafe_target_actions'] = ';'.join(row['unsafe_target_actions'])
        w.writerow(row)
print(f'Wrote {len(scenarios)} scenarios to {out_jsonl}')
